    public Object handleUnsubscriptionStatus(Client client, Object message)
    {
        //
        // {
        //     "event": "unsubscribed",
        //     "status": "OK",
        //     "chanId": CHANNEL_ID
        // }
        //
        Object channelId = this.safeString(message, "chanId");
        Object unSubChannel = Helpers.add("unsubscribe:", channelId);
        Object subMessageHash = this.safeString(client.subscriptions, unSubChannel);
        Object subscription = this.safeDict(client.subscriptions, Helpers.add("unsubscribe:", subMessageHash));
        ((java.util.Map<String,Object>)client.subscriptions).remove((String)unSubChannel);
        Object messageHashes = this.safeList(subscription, "messageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object subMessageHashes = this.safeList(subscription, "subMessageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object messageHash = Helpers.GetValue(messageHashes, i);
            Object subHash = Helpers.GetValue(subMessageHashes, i);
            this.cleanUnsubscription(client, subHash, messageHash);
        }
        this.cleanCache(subscription);
        return true;
    }

    public Object handleSubscriptionStatus(Client client, Object message)
    {
        //
        //     {
        //         "event": "subscribed",
        //         "channel": "book",
        //         "chanId": 67473,
        //         "symbol": "tBTCUSD",
        //         "prec": "P0",
        //         "freq": "F0",
        //         "len": "25",
        //         "pair": "BTCUSD"
        //     }
        //
        //   {
        //       event: 'subscribed',
        //       channel: 'candles',
        //       chanId: 128306,
        //       key: 'trade:1m:tBTCUST'
        //  }
        //
        Object channelId = this.safeString(message, "chanId");
        Helpers.addElementToObject(client.subscriptions, ((String)channelId), message);
        // store the opposite direction too for unWatch
        Object mappings = new java.util.HashMap<String, Object>() {{
            put( "book", "orderbook" );
            put( "candles", "ohlcv" );
            put( "ticker", "ticker" );
            put( "trades", "trades" );
        }};
        Object unifiedChannel = this.safeString(mappings, ((String)this.safeString(message, "channel")));
        if (Helpers.isTrue(Helpers.inOp(message, "key")))
        {
            // handle ohlcv differently because the message is different
            Object key = this.safeString(message, "key");
            Object subKeyId = Helpers.add("unsubscribe:", key);
            Helpers.addElementToObject(client.subscriptions, subKeyId, channelId);
        } else
        {
            Object marketId = this.safeString(message, "symbol");
            Object symbol = this.safeSymbol(marketId);
            if (Helpers.isTrue(!Helpers.isEqual(unifiedChannel, null)))
            {
                Object subId = Helpers.add(Helpers.add(Helpers.add("unsubscribe:", unifiedChannel), ":"), symbol);
                Helpers.addElementToObject(client.subscriptions, subId, channelId);
            }
        }
        return message;
    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object url = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "private");
            Client client = this.client(url);
            Object messageHash = "authenticated";
            io.github.ccxt.ws.Future future = client.reusableFuture((String)messageHash);
            Object authenticated = this.safeValue(client.subscriptions, messageHash);
            if (Helpers.isTrue(Helpers.isEqual(authenticated, null)))
            {
                Object nonce = this.milliseconds();
                Object payload = Helpers.add("AUTH", String.valueOf(nonce));
                Object signature = this.hmac(this.encode(payload), this.encode(this.secret), sha384(), "hex");
                Object eventVar = "auth";
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "apiKey", BitfinexCore.this.apiKey );
                    put( "authSig", signature );
                    put( "authNonce", nonce );
                    put( "authPayload", payload );
                    put( "event", eventVar );
                }};
                Object message = this.extend(request, parameters);
                this.watch(url, messageHash, message, messageHash, null);
            }
            return ((io.github.ccxt.ws.Future)future).getFuture().join();
        });

    }

    public void handleAuthenticationMessage(Client client, Object message)
    {
        Object messageHash = "authenticated";
        Object status = this.safeString(message, "status");
        if (Helpers.isTrue(Helpers.isEqual(status, "OK")))
        {
            // we resolve the future here permanently so authentication only happens once
            Object future = this.safeValue(client.futures, messageHash);
            ((io.github.ccxt.ws.Future)future).resolve(true);
        } else
        {
            var error = new AuthenticationError(this.json(message));
            client.reject(error, messageHash);
            // allows further authentication attempts
            if (Helpers.isTrue(Helpers.inOp(client.subscriptions, messageHash)))
            {
                ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
            }
        }
    }

    /**
     * @method
     * @name bitfinex#watchOrders
     * @description watches information on multiple orders made by the user
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object messageHash = "orders";
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                Object market = this.market(symbol);
                messageHash = Helpers.add(messageHash, Helpers.add(":", Helpers.GetValue(market, "id")));
            }
            Object orders = (this.subscribePrivate(messageHash)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(orders, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(orders, symbol, since, limit, true);
        });

    }

    public void handleOrders(Client client, Object message, Object subscription)
    {
        //
        // limit order
        //    [
        //        0,
        //        "on", // ou or oc
        //        [
        //           96923856256, // order id
        //           null, // gid
        //           1655029337026, // cid
        //           "tLTCUST", // symbol
        //           1655029337027, // created timestamp
        //           1655029337029, // updated timestamp
        //           0.1, // amount
        //           0.1, // amount_orig
        //           "EXCHANGE LIMIT", // order type
        //           null, // type_prev
        //           null, // mts_tif
        //           null, // placeholder
        //           0, // flags
        //           "ACTIVE", // status
        //           null,
        //           null,
        //           30, // price
        //           0, // price average
        //           0, // price_trailling
        //           0, // price_aux_limit
        //           null,
        //           null,
        //           null,
        //           0, // notify
        //           0,
        //           null,
        //           null,
        //           null,
        //           "BFX",
        //           null,
        //           null,
        //        ]
        //    ]
        //
        Object data = this.safeValue(message, 2, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object messageType = this.safeString(message, 1);
        if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
        {
            Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
            this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object orders = this.orders;
        Object symbolIds = new java.util.HashMap<String, Object>() {{}};
        if (Helpers.isTrue(Helpers.isEqual(messageType, "os")))
        {
            Object snapshotLength = Helpers.getArrayLength(data);
            if (Helpers.isTrue(Helpers.isEqual(snapshotLength, 0)))
            {
                return;
            }
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object value = Helpers.GetValue(data, i);
                Object parsed = this.parseWsOrder(value);
                Object symbol = Helpers.GetValue(parsed, "symbol");
                Helpers.addElementToObject(symbolIds, ((String)symbol), true);
                Helpers.callDynamically(orders, "append", new Object[]{parsed});
            }
        } else
        {
            Object parsed = this.parseWsOrder(data);
            Helpers.callDynamically(orders, "append", new Object[]{parsed});
            Object symbol = Helpers.GetValue(parsed, "symbol");
            Helpers.addElementToObject(symbolIds, ((String)symbol), true);
        }
        Object name = "orders";
        client.resolve(this.orders, name);
        Object keys = Helpers.objectKeys(symbolIds);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object symbol = Helpers.GetValue(keys, i);
            Object market = this.market(symbol);
            Object messageHash = Helpers.add(Helpers.add(name, ":"), Helpers.GetValue(market, "id"));
            client.resolve(this.orders, messageHash);
        }
    }

    public Object parseWsOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "ACTIVE", "open" );
            put( "CANCELED", "canceled" );
            put( "EXECUTED", "closed" );
            put( "PARTIALLY", "open" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        //   [
        //       97084883506, // order id
        //       null,
        //       1655110144596, // clientOrderId
        //       "tLTCUST", // symbol
        //       1655110144596, // created timestamp
        //       1655110144598, // updated timestamp
        //       0, // amount
        //       0.1, // amount_orig negative if sell order
        //       "EXCHANGE MARKET", // type
        //       null,
        //       null,
        //       null,
        //       0,
        //       "EXECUTED @ 42.821(0.1)", // status
        //       null,
        //       null,
        //       42.799, // price
        //       42.821, // price average
        //       0, // price trailling
        //       0, // price_aux_limit
        //       null,
        //       null,
        //       null,
        //       0,
        //       0,
        //       null,
        //       null,
        //       null,
        //       "BFX",
        //       null,
        //       null,
        //       {}
        //   ]
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(order, 0);
        Object clientOrderId = this.safeString(order, 1);
        Object marketId = this.safeString(order, 3);
        Object symbol = this.safeSymbol(marketId);
        market = this.safeMarket(symbol);
        Object amount = this.safeString(order, 7);
        Object side = "buy";
        if (Helpers.isTrue(Precise.stringLt(amount, "0")))
        {
            amount = Precise.stringAbs(amount);
            side = "sell";
        }
        Object remaining = Precise.stringAbs(this.safeString(order, 6));
        Object type = this.safeString(order, 8, "");
        if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.getIndexOf(type, "LIMIT"), Helpers.opNeg(1))))
        {
            type = "limit";
        } else if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.getIndexOf(type, "MARKET"), Helpers.opNeg(1))))
        {
            type = "market";
        }
        Object rawState = this.safeString(order, 13, "");
        Object stateParts = Helpers.split(rawState, " ");
        Object trimmedStatus = this.safeString(stateParts, 0);
        Object status = this.parseWsOrderStatus(trimmedStatus);
        Object price = this.safeString(order, 16);
        Object timestamp = this.safeInteger2(order, 5, 4);
        Object average = this.safeString(order, 17);
        Object stopPrice = this.omitZero(((String)this.safeString(order, 18)));
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalAmount = amount;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", BitfinexCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "side", finalSide );
            put( "price", price );
            put( "stopPrice", stopPrice );
            put( "triggerPrice", stopPrice );
            put( "average", average );
            put( "amount", finalAmount );
            put( "remaining", remaining );
            put( "filled", null );
            put( "status", status );
            put( "fee", null );
            put( "cost", null );
            put( "trades", null );
        }}, market);
    }

    public void handleMessage(Client client, Object message)
    {
        Object channelId = this.safeString(message, 0);
        //
        //     [
        //         1231,
        //         "hb",
        //     ]
        //
        // auth message
        //    {
        //        "event": "auth",
        //        "status": "OK",
        //        "chanId": 0,
        //        "userId": 3159883,
        //        "auth_id": "ac7108e7-2f26-424d-9982-c24700dc02ca",
        //        "caps": {
        //          "orders": { read: 1, write: 1 },
        //          "account": { read: 1, write: 1 },
        //          "funding": { read: 1, write: 1 },
        //          "history": { read: 1, write: 0 },
        //          "wallets": { read: 1, write: 1 },
        //          "withdraw": { read: 0, write: 1 },
        //          "positions": { read: 1, write: 1 },
        //          "ui_withdraw": { read: 0, write: 0 }
        //        }
        //    }
        //
        if (Helpers.isTrue(Helpers.isArray(message)))
        {
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(message, 1), "hb")))
            {
                return;  // skip heartbeats within subscription channels for now
            }
            Object subscription = this.safeValue(client.subscriptions, ((String)channelId), new java.util.HashMap<String, Object>() {{}});
            Object channel = this.safeString(subscription, "channel");
            Object name = this.safeString(message, 1);
            Object publicMethods = new java.util.HashMap<String, Object>() {{
                put( "book", "handleOrderBook");
                put( "cs", "handleChecksum");
                put( "candles", "handleOHLCV");
                put( "ticker", "handleTicker");
                put( "trades", "handleTrades");
            }};
            Object privateMethods = new java.util.HashMap<String, Object>() {{
                put( "os", "handleOrders");
                put( "ou", "handleOrders");
                put( "on", "handleOrders");
                put( "oc", "handleOrders");
                put( "wu", "handleBalance");
                put( "ws", "handleBalance");
                put( "tu", "handleMyTrade");
            }};
            Object method = null;
            if (Helpers.isTrue(Helpers.isEqual(channelId, "0")))
            {
                method = this.safeValue(privateMethods, ((String)name));
            } else
            {
                method = this.safeValue2(publicMethods, ((String)name), ((String)channel));
            }
            if (Helpers.isTrue(!Helpers.isEqual(method, null)))
            {
                Helpers.callDynamically(this, method, new Object[] {client, message, subscription});
            }
        } else
        {
            Object eventVar = this.safeString(message, "event");
            if (Helpers.isTrue(!Helpers.isEqual(eventVar, null)))
            {
                Object methods = new java.util.HashMap<String, Object>() {{
                    put( "info", "handleSystemStatus");
                    put( "subscribed", "handleSubscriptionStatus");
                    put( "unsubscribed", "handleUnsubscriptionStatus");
                    put( "auth", "handleAuthenticationMessage");
                }};
                Object method = this.safeValue(methods, eventVar);
                if (Helpers.isTrue(!Helpers.isEqual(method, null)))
                {
                    Helpers.callDynamically(this, method, new Object[] {client, message});
                }
            }
        }
    }
